**Key Implementation Details:**
- Task aliases are applied first (e.g., "sentiment-analysis" → "text-classification")
- Pipeline info is looked up in SUPPORTED_TASKS (splits on "_" for tasks like "translation_xx_to_yy")
- Falls back to default model if none specified
- `loadItems()` helper loads all components (tokenizer, model, processor) in parallel
- Constructs a Map of components to load, passing to `loadItems()`
- Progress callback is dispatched when ready
- Finally instantiates the appropriate pipeline class with loaded components

---

### 8. HELPER FUNCTION: loadItems (Lines 3523-3580)

```javascript
/**
 * Helper function to get applicable model, tokenizer, or processor classes for a given model.
 * @param {Map<string, any>} mapping The mapping of names to classes, arrays of classes, or null.
 * @param {string} model The name of the model to load.
 * @param {import('./utils/hub.js').PretrainedOptions} pretrainedOptions The options to pass to the `from_pretrained` method.
 * @private
 */
async function loadItems(mapping, model, pretrainedOptions) {

    const result = Object.create(null);

    /**@type {Promise[]} */
    const promises = [];
    for (const [name, cls] of mapping.entries()) {
        if (!cls) continue;

        /**@type {Promise} */
        let promise;
        if (Array.isArray(cls)) {
            promise = new Promise(async (resolve, reject) => {
                let e;
                for (const c of cls) {
                    if (c === null) {
                        // If null, we resolve it immediately, meaning the relevant
                        // class was not found, but it is optional.
                        resolve(null);
                        return;
                    }
                    try {
                        resolve(await c.from_pretrained(model, pretrainedOptions));
                        return;
                    } catch (err) {
                        if (err.message?.includes('Unsupported model type')) {
                            // If the error is due to an unsupported model type, we
                            // save the error and try the next class.
                            e = err;
                        } else if (err.message?.includes('Could not locate file')) {
                            e = err;
                        } else {
                            reject(err);
                            return;
                        }

                    }
                }
                reject(e);
            })
        } else {
            promise = cls.from_pretrained(model, pretrainedOptions);
        }

        result[name] = promise;
        promises.push(promise);
    }

    // Wait for all promises to resolve (in parallel)
    await Promise.all(promises);

    // Then assign to result
    for (const [name, promise] of Object.entries(result)) {
        result[name] = await promise;
    }

    return result;
}
```

**Key Pattern:**
- Handles single classes and arrays of classes (fallback strategy)
- When array of classes provided, tries each in order until one succeeds
- Null in array means optional component (resolves immediately)
- All components load in parallel via `Promise.all()`
- Returns object with keys: `tokenizer`, `model`, `processor` (values are loaded instances or null)

