```

---

### Step 2 — Add JSDoc typedefs, callback, and class

Insert the following block immediately **after** the `DocumentQuestionAnsweringPipeline` class closes (after line 2779), before `TextToAudioPipeline` begins.

```js
/**
 * @typedef {Object} ImageTextToTextOutput
 * @property {string} generated_text The generated text.
 *
 * @typedef {Object} ImageTextToTextPipelineOptions Parameters specific to image-text-to-text pipelines.
 * @property {boolean} [skip_special_tokens=true] Whether to remove special tokens from the output.
 *
 * @callback ImageTextToTextPipelineCallback Generate text from the image and text prompt given as inputs.
 * @param {ImageInput} image The input image.
 * @param {string} text The text prompt describing what to do with the image.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput[]>} An array of objects containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using `AutoModelForImageTextToText`. This pipeline generates
 * text from an image and a text prompt.
 *
 * **Example:** Describe an image in detail w/ `onnx-community/Florence-2-base-ft`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'onnx-community/Florence-2-base-ft');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(image, '<DETAILED_CAPTION>');
 * // [{ generated_text: 'Two cats are lying on a couch.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(image, text, generate_kwargs = {}) {

        // Preprocess image
        const preparedImage = (await prepareImages(image))[0];
        const image_inputs = await this.processor(preparedImage);

        // Tokenize text prompt
        const text_inputs = this.tokenizer(text, {
            padding: true,
            truncation: true,
        });

        // Run model with both image and text inputs
        const output = await this.model.generate({
            ...image_inputs,
            ...text_inputs,
            ...generate_kwargs,
        });

        // Decode output tokens to text
        const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output), {
            skip_special_tokens: true,
        }).map(x => ({ generated_text: x.trim() }));

        return decoded;
    }
}
```

**Design notes:**
- Spreads both `image_inputs` (contains `pixel_values`) and `text_inputs` (contains `input_ids`, `attention_mask`) into `generate()`. This is the correct generic approach for decoder-style VLMs (LLaVA, Florence-2, Qwen2-VL, etc.) where both image and text are encoder inputs, not separate encoder/decoder inputs as in `DocumentQuestionAnsweringPipeline`.
- Returns a flat array `[{ generated_text }]` (always an array, not conditionally batched), consistent with the stated requirements.
- Reuses `prepareImages()` and `TextImagePipelineConstructorArgs` — no new helpers needed.

